// GinServerOptions provides options for the Gin server.
type GinServerOptions struct {
	BaseURL      string
	Middlewares  []MiddlewareFunc
	ErrorHandler func(*gin.Context, error, int)
}

// RegisterHandlers creates http.Handler with routing matching OpenAPI spec.
func RegisterHandlers(router gin.IRouter, si ServerInterface) {
	RegisterHandlersWithOptions(router, si, GinServerOptions{})
}

// RegisterHandlersWithOptions creates http.Handler with additional options
func RegisterHandlersWithOptions(router gin.IRouter, si ServerInterface, options GinServerOptions) {
	errorHandler := options.ErrorHandler
	if errorHandler == nil {
		errorHandler = func(c *gin.Context, err error, statusCode int) {
			c.JSON(statusCode, gin.H{"msg": err.Error()})
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandler:       errorHandler,
	}

	router.GET(options.BaseURL+"/global", wrapper.GetGlobalConfig)
	router.PUT(options.BaseURL+"/global", wrapper.UpdateGlobalConfig)
	router.POST(options.BaseURL+"/login", wrapper.Login)
	router.GET(options.BaseURL+"/pipelines", wrapper.ListPipelines)
	router.POST(options.BaseURL+"/pipelines", wrapper.CreatePipeline)
	router.DELETE(options.BaseURL+"/pipelines/:id", wrapper.DeletePipeline)
	router.GET(options.BaseURL+"/pipelines/:id", wrapper.GetPipeline)
	router.PUT(options.BaseURL+"/pipelines/:id", wrapper.UpdatePipeline)
	router.GET(options.BaseURL+"/pipelines/:id/metrics", wrapper.StreamPipelineMetrics)
	router.POST(options.BaseURL+"/pipelines/:id/restart", wrapper.RestartPipeline)
	router.GET(options.BaseURL+"/pipelines/:id/status", wrapper.GetPipelineStatus)
	router.GET(options.BaseURL+"/sinks", wrapper.ListSinks)
	router.POST(options.BaseURL+"/sinks", wrapper.CreateSink)
	router.DELETE(options.BaseURL+"/sinks/:id", wrapper.DeleteSink)
	router.GET(options.BaseURL+"/sinks/:id", wrapper.GetSink)
	router.PUT(options.BaseURL+"/sinks/:id", wrapper.UpdateSink)
	router.GET(options.BaseURL+"/sources", wrapper.ListSources)
	router.POST(options.BaseURL+"/sources", wrapper.CreateSource)
	router.DELETE(options.BaseURL+"/sources/:id", wrapper.DeleteSource)
	router.GET(options.BaseURL+"/sources/:id", wrapper.GetSource)
	router.PUT(options.BaseURL+"/sources/:id", wrapper.UpdateSource)
	router.GET(options.BaseURL+"/sources/:id/schema", wrapper.GetSourceSchema)
	router.GET(options.BaseURL+"/sources/:id/tables", wrapper.ListSourceTables)
	router.GET(options.BaseURL+"/stats/history", wrapper.GetStatsHistory)
	router.GET(options.BaseURL+"/stats/summary", wrapper.GetStatsSummary)
	router.GET(options.BaseURL+"/workers/:id/heartbeat", wrapper.GetWorkerHeartbeat)
}

